// global.d.ts

// Allow importing CSS files
declare module '*.css';
declare module '*.scss';
declare module '*.sass';

// Allow importing image files as static assets (URLs)
declare module '*.png';
declare module '*.jpg';
declare module '*.jpeg';
declare module '*.gif';
declare module '*.webp';
declare module '*.avif';
declare module '*.svg';
declare module '*.ico';
declare module '*.bmp';
